    amount: number;
    expires: Date;
  };
}

// To update discount partially
function updateDiscount(product: Product, discountUpdates: Partial<Product["discount"]>) {
  if (product.discount) {
    product.discount = { ...product.discount, ...discountUpdates };
  }
}

def count_up_to(max):
    count = 1
    while count <= max:
        yield count
        count += 1

for number in count_up_to(5):
    print(number)

def read_large_file(file_path):
    with open(file_path, 'r') as file:
        for line in file:
            yield line.strip()  # Yield one line at a time without newline

# Example usage:
